  <programme start="20260328030500 +0000" stop="20260328035500 +0000" channel="lovenaturehd.unifitv">
    <title lang="en">Wild Rockies</title>
    <desc lang="en">Survival in the forest means maintaining a delicate balance between growth and destruction and death and rebirth - a forest should be in a constant state of regeneration. When trees get too tall they block all the sunlight from hitting the ground, which means grasses and smaller shrubs can't grow, diminishing habitat for animals like elk, moose, caribou, and wolves.</desc>
    <category lang="en">Wildlife</category>
    <episode-num system="xmltv_ns">0.3.</episode-num>
    <episode-num system="onscreen">S1E4</episode-num>
